{
  "name": "Pallet-Based Monitor Management System",
  "description": "A comprehensive logistics solution for managing monitor inventory by pallets, featuring real-time tracking, manifest generation, and Excel export capabilities.",
  "requestFramePermissions": []
}

export enum MonitorGrade {
  GOOD = '양품',
  BAD = '불량'
}

export enum PowerType {
  POWER = '파워모델',
  ADAPTER = '어댑터모델'
}

export interface MonitorItem {
  id: string;
  grade: MonitorGrade;
  brand: string;
  inch: string;
  powerType: PowerType;
  quantity: number;
}

export interface Pallet {
  id: string; // P-YYYYMMDD-XXXX
  department: string;
  lastUpdated: string;
  memo: string;
  items: MonitorItem[];
}

export interface FilterOptions {
  department: string;
  grade: string;
  brand: string;
  inch: string;
  powerType: string;
}

export const BRANDS = ['삼성', 'LG', 'Lenovo', 'HP', 'Dell', '기타'];
export const INCHES = ['19', '21', '22', '24', '27', '32', '34', '기타'];
export const DEPARTMENTS = ['영업1본부', '영업2본부', '물류지원팀', '렌탈사업부', '중고사업부'];

export const STORAGE_KEY = 'monitor_management_pallets';

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { GoogleGenAI } from "@google/genai";
import { Pallet } from "./types";

export const getInventoryInsights = async (pallets: Pallet[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const inventoryData = pallets.map(p => ({
    id: p.id,
    dept: p.department,
    items: p.items.map(i => `${i.grade} ${i.brand} ${i.inch}인치 x${i.quantity}`)
  }));

  const prompt = `
    다음은 현재 물류 창고의 팔레트별 모니터 적재 현황입니다.
    ${JSON.stringify(inventoryData, null, 2)}

    이 데이터를 바탕으로 창고 관리자에게 다음 정보를 3줄 이내로 간략하게 한국어로 요약해 주세요:
    1. 현재 가장 많이 적재된 브랜드와 사양
    2. 저단 팔레트(수량이 적은 팔레트) 합치기 제안
    3. 전체적인 재고 상태 요약
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Insight Error:", error);
    return "재고 분석 정보를 가져오는 데 실패했습니다.";
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { Pallet, MonitorGrade, PowerType, FilterOptions } from './types';
import { STORAGE_KEY } from './constants';
import Dashboard from './components/Dashboard';
import PalletList from './components/PalletList';
import PalletForm from './components/PalletForm';
import ManifestView from './components/ManifestView';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import { getInventoryInsights } from './geminiService';

const App: React.FC = () => {
  const [pallets, setPallets] = useState<Pallet[]>([]);
  const [view, setView] = useState<'dashboard' | 'list' | 'add' | 'manifest'>('dashboard');
  const [selectedPalletId, setSelectedPalletId] = useState<string | null>(null);
  const [insights, setInsights] = useState<string>('분석 중...');
  const [searchQuery, setSearchQuery] = useState('');

  // Initial Load
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      setPallets(JSON.parse(saved));
    }
  }, []);

  // Persist Changes
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(pallets));
  }, [pallets]);

  // AI Insight Fetcher
  useEffect(() => {
    if (pallets.length > 0) {
      const fetchInsights = async () => {
        const text = await getInventoryInsights(pallets);
        setInsights(text || '');
      };
      fetchInsights();
    } else {
      setInsights('데이터가 없습니다.');
    }
  }, [pallets]);

  const addOrUpdatePallet = (pallet: Pallet) => {
    setPallets(prev => {
      const index = prev.findIndex(p => p.id === pallet.id);
      if (index > -1) {
        const updated = [...prev];
        updated[index] = pallet;
        return updated;
      }
      return [pallet, ...prev];
    });
    setView('list');
  };

  const deletePallet = (id: string) => {
    if (window.confirm('정말 삭제하시겠습니까?')) {
      setPallets(prev => prev.filter(p => p.id !== id));
    }
  };

  const selectedPallet = useMemo(() => 
    pallets.find(p => p.id === selectedPalletId), 
  [pallets, selectedPalletId]);

  return (
    <div className="flex min-h-screen">
      {/* Sidebar - Desktop Only for now */}
      <div className="no-print">
        <Sidebar currentView={view} setView={setView} />
      </div>

      <main className="flex-1 flex flex-col min-w-0 bg-slate-50">
        <Header className="no-print" />

        <div className="p-4 md:p-8 flex-1 overflow-auto max-w-7xl mx-auto w-full">
          {view === 'dashboard' && (
            <Dashboard 
              pallets={pallets} 
              insights={insights} 
              onViewList={() => setView('list')} 
            />
          )}

          {view === 'list' && (
            <PalletList 
              pallets={pallets} 
              onEdit={(id) => { setSelectedPalletId(id); setView('add'); }}
              onDelete={deletePallet}
              onPrint={(id) => { setSelectedPalletId(id); setView('manifest'); }}
              onAddNew={() => { setSelectedPalletId(null); setView('add'); }}
            />
          )}

          {view === 'add' && (
            <PalletForm 
              initialPallet={selectedPallet} 
              onSave={addOrUpdatePallet}
              onCancel={() => setView('list')}
            />
          )}

          {view === 'manifest' && selectedPallet && (
            <ManifestView 
              pallet={selectedPallet} 
              onBack={() => setView('list')} 
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

