export default Header;

import React from 'react';
import { Pallet, MonitorGrade } from '../types';

interface DashboardProps {
  pallets: Pallet[];
  insights: string;
  onViewList: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ pallets, insights, onViewList }) => {
  const stats = React.useMemo(() => {
    let totalMonitors = 0;
    let goodMonitors = 0;
    let badMonitors = 0;
    const brandCounts: Record<string, number> = {};

    pallets.forEach(p => {
      p.items.forEach(i => {
        totalMonitors += i.quantity;
        if (i.grade === MonitorGrade.GOOD) goodMonitors += i.quantity;
        else badMonitors += i.quantity;

        brandCounts[i.brand] = (brandCounts[i.brand] || 0) + i.quantity;
      });
    });

    const topBrands = Object.entries(brandCounts)
      .sort(([, a], [, b]) => b - a)
      .slice(0, 5);

    return { totalPallets: pallets.length, totalMonitors, goodMonitors, badMonitors, topBrands };
  }, [pallets]);

  return (
    <div className="space-y-6 animate-fadeIn">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-900">창고 운영 현황</h2>
        <button 
          onClick={onViewList}
          className="text-blue-600 hover:text-blue-700 font-medium flex items-center space-x-1"
        >
          <span>전체 리스트 보기</span>
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
          </svg>
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title="총 팔레트 수" value={stats.totalPallets} unit="개" color="bg-blue-500" />
        <StatCard title="총 모니터 재고" value={stats.totalMonitors} unit="대" color="bg-indigo-500" />
        <StatCard title="양품 수량" value={stats.goodMonitors} unit="대" color="bg-emerald-500" />
        <StatCard title="불량/파손" value={stats.badMonitors} unit="대" color="bg-rose-500" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Brand Chart Replacement */}
        <div className="lg:col-span-2 bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <h3 className="text-lg font-semibold mb-6">주요 제조사별 점유율</h3>
          <div className="space-y-4">
            {stats.topBrands.map(([brand, count]) => {
              const percentage = stats.totalMonitors > 0 ? (count / stats.totalMonitors) * 100 : 0;
              return (
                <div key={brand}>
                  <div className="flex justify-between text-sm mb-1 font-medium">
                    <span>{brand}</span>
                    <span>{count}대 ({percentage.toFixed(1)}%)</span>
                  </div>
                  <div className="w-full bg-slate-100 rounded-full h-2">
                    <div 
                      className="bg-blue-600 h-2 rounded-full transition-all duration-1000" 
                      style={{ width: `${percentage}%` }}
                    />
                  </div>
                </div>
              );
            })}
            {stats.topBrands.length === 0 && <div className="text-center py-10 text-slate-400">등록된 데이터가 없습니다.</div>}
          </div>
        </div>

        {/* AI Insight Box */}
        <div className="bg-gradient-to-br from-indigo-50 to-blue-50 p-6 rounded-xl border border-blue-100 shadow-sm flex flex-col">
          <div className="flex items-center space-x-2 mb-4">
            <div className="p-2 bg-blue-600 rounded-lg">
              <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
            </div>
            <h3 className="text-lg font-semibold text-blue-900">창고 운영 AI 제안</h3>
          </div>
          <p className="text-blue-800 text-sm leading-relaxed flex-1 whitespace-pre-wrap">
            {insights}
          </p>
          <div className="mt-4 pt-4 border-t border-blue-200">
            <span className="text-[10px] text-blue-400 font-bold uppercase tracking-wider">Gemini 3 Flash Powered</span>
          </div>
        </div>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ title: string; value: number; unit: string; color: string }> = ({ title, value, unit, color }) => (
  <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-shadow">
    <p className="text-sm font-medium text-slate-500 mb-2">{title}</p>
    <div className="flex items-baseline space-x-1">
      <span className="text-3xl font-bold text-slate-900">{value.toLocaleString()}</span>
      <span className="text-sm font-medium text-slate-600">{unit}</span>
    </div>
    <div className={`mt-4 h-1 w-12 rounded-full ${color}`} />
  </div>
);

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { Pallet, MonitorGrade, PowerType } from '../types';
import { DEPARTMENTS, BRANDS, INCHES } from '../constants';

interface PalletListProps {
  pallets: Pallet[];
  onEdit: (id: string) => void;
  onDelete: (id: string) => void;
  onPrint: (id: string) => void;
  onAddNew: () => void;
}

const PalletList: React.FC<PalletListProps> = ({ pallets, onEdit, onDelete, onPrint, onAddNew }) => {
  const [filter, setFilter] = useState({
    dept: '',
    brand: '',
    grade: '',
  });

  const filteredPallets = useMemo(() => {
    return pallets.filter(p => {
      const matchDept = !filter.dept || p.department === filter.dept;
      const matchBrand = !filter.brand || p.items.some(i => i.brand === filter.brand);
      const matchGrade = !filter.grade || p.items.some(i => i.grade === filter.grade);
      return matchDept && matchBrand && matchGrade;
    });
  }, [pallets, filter]);

  const exportToCsv = () => {
    // Generate CSV content
    const headers = ['팔레트ID', '본부명', '구분', '브랜드', '인치', '전원방식', '수량', '메모', '최종업데이트'];
    const rows = filteredPallets.flatMap(p => 
      p.items.map(i => [
        p.id,
        p.department,
        i.grade,
        i.brand,
        i.inch,
        i.powerType,
        i.quantity,
        p.memo,
        p.lastUpdated
      ])
    );

    const csvContent = [
      '\uFEFF' + headers.join(','),
      ...rows.map(r => r.map(c => `"${c}"`).join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `monitor_inventory_${new Date().toISOString().slice(0, 10)}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-4">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <h2 className="text-2xl font-bold text-slate-900">팔레트 재고 현황</h2>
        <div className="flex space-x-2">
          <button 
            onClick={exportToCsv}
            className="px-4 py-2 border border-slate-300 rounded-lg text-slate-700 font-medium hover:bg-slate-50 flex items-center space-x-2"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
            </svg>
            <span>Excel(CSV) 내보내기</span>
          </button>
          <button 
            onClick={onAddNew}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg font-medium hover:bg-blue-700 flex items-center space-x-2"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
            </svg>
            <span>신규 팔레트 등록</span>
          </button>
        </div>
      </div>

      {/* Filters */}
      <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm grid grid-cols-1 md:grid-cols-3 gap-4">
        <div>
          <label className="block text-xs font-bold text-slate-500 uppercase mb-1">자산 주체 본부</label>
          <select 
            value={filter.dept}
            onChange={e => setFilter(f => ({ ...f, dept: e.target.value }))}
            className="w-full border-slate-200 rounded-lg text-sm focus:ring-blue-500 focus:border-blue-500"
          >
            <option value="">전체 본부</option>
            {DEPARTMENTS.map(d => <option key={d} value={d}>{d}</option>)}
          </select>
        </div>
        <div>
          <label className="block text-xs font-bold text-slate-500 uppercase mb-1">제조사 브랜드</label>
          <select 
            value={filter.brand}
            onChange={e => setFilter(f => ({ ...f, brand: e.target.value }))}
            className="w-full border-slate-200 rounded-lg text-sm focus:ring-blue-500 focus:border-blue-500"
          >
            <option value="">전체 브랜드</option>
            {BRANDS.map(b => <option key={b} value={b}>{b}</option>)}
          </select>
        </div>
        <div>
          <label className="block text-xs font-bold text-slate-500 uppercase mb-1">양/불 구분</label>
          <select 
            value={filter.grade}
            onChange={e => setFilter(f => ({ ...f, grade: e.target.value }))}
            className="w-full border-slate-200 rounded-lg text-sm focus:ring-blue-500 focus:border-blue-500"
          >
            <option value="">전체 상태</option>
            <option value={MonitorGrade.GOOD}>양품</option>
            <option value={MonitorGrade.BAD}>불량</option>
          </select>
        </div>
      </div>

      {/* Table */}
      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-200">
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">팔레트 ID</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">본부 / 메모</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">적재 정보 (요약)</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">총 수량</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">최종 업데이트</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider text-right">관리</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-200">
              {filteredPallets.map(p => {
                const totalQty = p.items.reduce((sum, item) => sum + item.quantity, 0);
                return (
                  <tr key={p.id} className="hover:bg-slate-50 transition-colors group">
                    <td className="px-6 py-4">
                      <span className="font-mono text-sm font-bold text-blue-600">{p.id}</span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="font-medium text-slate-900">{p.department}</div>
                      <div className="text-xs text-slate-400 line-clamp-1">{p.memo || '-'}</div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex flex-wrap gap-1">
                        {p.items.slice(0, 2).map((item, idx) => (
                          <span key={idx} className={`text-[10px] px-1.5 py-0.5 rounded font-bold ${item.grade === MonitorGrade.GOOD ? 'bg-emerald-100 text-emerald-700' : 'bg-rose-100 text-rose-700'}`}>
                            {item.brand} {item.inch}" ({item.quantity})
                          </span>
                        ))}
                        {p.items.length > 2 && <span className="text-[10px] text-slate-400 font-medium">외 {p.items.length - 2}건</span>}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className="text-lg font-bold text-slate-700">{totalQty}대</span>
                    </td>
                    <td className="px-6 py-4 text-sm text-slate-500">
                      {p.lastUpdated}
                    </td>
