            <label className="block text-sm font-bold text-slate-700 mb-2">자산 주체 본부 *</label>
            <select 
              value={department}
              onChange={e => setDepartment(e.target.value)}
              className="w-full border-slate-200 rounded-lg focus:ring-blue-500 focus:border-blue-500"
