import React, { useState, useEffect, useMemo } from 'react';
import { Pallet, MonitorGrade, PowerType, FilterOptions, MonitorItem } from './types';
import { STORAGE_KEY } from './constants';
import Dashboard from './components/Dashboard';
import PalletList from './components/PalletList';
import PalletForm from './components/PalletForm';
import ManifestView from './components/ManifestView';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import { getInventoryInsights } from './geminiService';

const App: React.FC = () => {
  const [pallets, setPallets] = useState<Pallet[]>([]);
  const [view, setView] = useState<'dashboard' | 'list' | 'add' | 'manifest'>('dashboard');
  const [selectedPalletId, setSelectedPalletId] = useState<string | null>(null);
  const [insights, setInsights] = useState<string>('분석 중...');

  // Initial Load
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      setPallets(JSON.parse(saved));
    }
  }, []);

  // Persist Changes
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(pallets));
  }, [pallets]);

  // AI Insight Fetcher
  useEffect(() => {
    if (pallets.length > 0) {
      const fetchInsights = async () => {
        const text = await getInventoryInsights(pallets);
        setInsights(text || '');
      };
      fetchInsights();
    } else {
      setInsights('데이터가 없습니다.');
    }
  }, [pallets]);

  const addOrUpdatePallet = (pallet: Pallet) => {
    setPallets(prev => {
      const index = prev.findIndex(p => p.id === pallet.id);
      if (index > -1) {
        const updated = [...prev];
        updated[index] = pallet;
        return updated;
      }
      return [pallet, ...prev];
    });
    setView('list');
  };

  const updatePallet = (id: string, updates: Partial<Pallet>) => {
    setPallets(prev => prev.map(p => p.id === id ? { ...p, ...updates, lastUpdated: new Date().toLocaleString() } : p));
  };

  const deletePallet = (id: string) => {
    if (window.confirm('정말 삭제하시겠습니까?')) {
      setPallets(prev => prev.filter(p => p.id !== id));
    }
  };

  const selectedPallet = useMemo(() => 
    pallets.find(p => p.id === selectedPalletId), 
  [pallets, selectedPalletId]);

  return (
    <div className="flex min-h-screen">
      <div className="no-print">
        <Sidebar currentView={view} setView={setView} />
      </div>

      <main className="flex-1 flex flex-col min-w-0 bg-slate-50">
        <Header className="no-print" />

        <div className="p-4 md:p-8 flex-1 overflow-auto max-w-7xl mx-auto w-full">
          {view === 'dashboard' && (
            <Dashboard 
              pallets={pallets} 
              insights={insights} 
              onViewList={() => setView('list')} 
            />
          )}

          {view === 'list' && (
            <PalletList 
              pallets={pallets} 
              onEdit={(id) => { setSelectedPalletId(id); setView('add'); }}
              onUpdatePallet={updatePallet}
              onDelete={deletePallet}
              onPrint={(id) => { setSelectedPalletId(id); setView('manifest'); }}
              onAddNew={() => { setSelectedPalletId(null); setView('add'); }}
            />
          )}

          {view === 'add' && (
            <PalletForm 
              initialPallet={selectedPallet} 
              onSave={addOrUpdatePallet}
              onCancel={() => setView('list')}
            />
          )}

          {view === 'manifest' && selectedPallet && (
            <ManifestView 
              pallet={selectedPallet} 
              onBack={() => setView('list')} 
            />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Pallet, MonitorGrade, MonitorItem } from '../types';
import { DEPARTMENTS, BRANDS } from '../constants';

interface PalletListProps {
  pallets: Pallet[];
  onEdit: (id: string) => void;
  onUpdatePallet: (id: string, updates: Partial<Pallet>) => void;
  onDelete: (id: string) => void;
  onPrint: (id: string) => void;
  onAddNew: () => void;
}

const PalletList: React.FC<PalletListProps> = ({ pallets, onEdit, onUpdatePallet, onDelete, onPrint, onAddNew }) => {
  const [filter, setFilter] = useState({
    dept: '',
    brand: '',
    grade: '',
  });

  const [editingId, setEditingId] = useState<string | null>(null);
  const [tempItems, setTempItems] = useState<MonitorItem[]>([]);

  const filteredPallets = useMemo(() => {
    return pallets.filter(p => {
      const matchDept = !filter.dept || p.department === filter.dept;
      const matchBrand = !filter.brand || p.items.some(i => i.brand === filter.brand);
      const matchGrade = !filter.grade || p.items.some(i => i.grade === filter.grade);
      return matchDept && matchBrand && matchGrade;
    });
  }, [pallets, filter]);

  const startInlineEdit = (p: Pallet) => {
    setEditingId(p.id);
    setTempItems(JSON.parse(JSON.stringify(p.items)));
  };

  const handleInlineSave = (id: string) => {
    onUpdatePallet(id, { items: tempItems });
    setEditingId(null);
  };

  const updateTempItemQty = (itemId: string, qty: number) => {
    setTempItems(prev => prev.map(item => item.id === itemId ? { ...item, quantity: Math.max(0, qty) } : item));
  };

  const exportToCsv = () => {
    const headers = ['팔레트ID', '본부명', '구분', '브랜드', '인치', '전원방식', '수량', '메모', '최종업데이트'];
    const rows = filteredPallets.flatMap(p => 
      p.items.map(i => [
        p.id,
        p.department,
        i.grade,
        i.brand,
        i.inch,
        i.powerType,
        i.quantity,
        p.memo,
        p.lastUpdated
      ])
    );

    const csvContent = [
      '\uFEFF' + headers.join(','),
      ...rows.map(r => r.map(c => `"${c}"`).join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `monitor_inventory_${new Date().toISOString().slice(0, 10)}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-4">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <h2 className="text-2xl font-bold text-slate-900">팔레트 재고 현황</h2>
        <div className="flex space-x-2">
          <button 
            onClick={exportToCsv}
            className="px-4 py-2 border border-slate-300 rounded-lg text-slate-700 font-medium hover:bg-slate-50 flex items-center space-x-2"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
