import React, { useState, useMemo } from 'react';
import { Pallet, MonitorGrade, MonitorItem } from '../types';
import { DEPARTMENTS, BRANDS } from '../constants';

interface PalletListProps {
  pallets: Pallet[];
  onEdit: (id: string) => void;
  onUpdatePallet: (id: string, updates: Partial<Pallet>) => void;
  onDelete: (id: string) => void;
  onPrint: (id: string) => void;
  onAddNew: () => void;
}

const PalletList: React.FC<PalletListProps> = ({ pallets, onEdit, onUpdatePallet, onDelete, onPrint, onAddNew }) => {
  const [filter, setFilter] = useState({
    dept: '',
    brand: '',
    grade: '',
  });

  const filteredPallets = useMemo(() => {
    return pallets.filter(p => {
      const matchDept = !filter.dept || p.department === filter.dept;
      const matchBrand = !filter.brand || p.items.some(i => i.brand === filter.brand);
      const matchGrade = !filter.grade || p.items.some(i => i.grade === filter.grade);
      return matchDept && matchBrand && matchGrade;
    });
  }, [pallets, filter]);

  const handleQuantityChange = (palletId: string, itemId: string, newQty: number) => {
    const pallet = pallets.find(p => p.id === palletId);
    if (!pallet) return;

    const updatedItems = pallet.items.map(item => 
      item.id === itemId ? { ...item, quantity: Math.max(0, newQty) } : item
    );

    onUpdatePallet(palletId, { items: updatedItems });
  };

  const exportToCsv = () => {
    const headers = ['팔레트ID', '본부명', '구분', '브랜드', '인치', '전원방식', '수량', '메모', '최종업데이트'];
    const rows = filteredPallets.flatMap(p => 
      p.items.map(i => [
        p.id,
        p.department,
        i.grade,
        i.brand,
        i.inch,
        i.powerType,
        i.quantity,
        p.memo,
        p.lastUpdated
      ])
    );

    const csvContent = [
      '\uFEFF' + headers.join(','),
      ...rows.map(r => r.map(c => `"${c}"`).join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `monitor_inventory_${new Date().toISOString().slice(0, 10)}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="space-y-4">
      <style>{`
        /* Remove arrows from number input */
        input::-webkit-outer-spin-button,
        input::-webkit-inner-spin-button {
          -webkit-appearance: none;
          margin: 0;
        }
        input[type=number] {
          -moz-appearance: textfield;
        }
      `}</style>
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <h2 className="text-2xl font-bold text-slate-900">팔레트 재고 현황</h2>
        <div className="flex space-x-2">
          <button 
            onClick={exportToCsv}
            className="px-4 py-2 border border-slate-300 rounded-lg text-slate-700 font-medium hover:bg-slate-50 flex items-center space-x-2"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
            </svg>
            <span>Excel 내보내기</span>
          </button>
          <button 
            onClick={onAddNew}
            className="px-4 py-2 bg-blue-600 text-white rounded-lg font-medium hover:bg-blue-700 flex items-center space-x-2"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
            </svg>
            <span>신규 팔레트 등록</span>
          </button>
        </div>
      </div>

      <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm grid grid-cols-1 md:grid-cols-3 gap-4">
        <div>
          <label className="block text-xs font-bold text-slate-500 uppercase mb-1">자산 주체 본부</label>
          <select 
            value={filter.dept}
            onChange={e => setFilter(f => ({ ...f, dept: e.target.value }))}
            className="w-full border-slate-200 rounded-lg text-sm focus:ring-blue-500 focus:border-blue-500"
          >
            <option value="">전체 본부</option>
            {DEPARTMENTS.map(d => <option key={d} value={d}>{d}</option>)}
          </select>
        </div>
        <div>
          <label className="block text-xs font-bold text-slate-500 uppercase mb-1">제조사 브랜드</label>
          <select 
            value={filter.brand}
            onChange={e => setFilter(f => ({ ...f, brand: e.target.value }))}
            className="w-full border-slate-200 rounded-lg text-sm focus:ring-blue-500 focus:border-blue-500"
          >
            <option value="">전체 브랜드</option>
            {BRANDS.map(b => <option key={b} value={b}>{b}</option>)}
          </select>
        </div>
        <div>
